package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;
    private Token reusableToken;
    private List<String> recordList;
    private Map<String, Integer> headerMap;

    @BeforeEach
    void setUp() throws Exception {
        // Mock Lexer
        lexerMock = mock(Lexer.class);

        // Prepare headerMap (empty for simplicity)
        headerMap = Map.of();

        // Create instance of CSVParser with mocked Lexer and headerMap using reflection
        parser = new CSVParser(mock(java.io.Reader.class), mock(CSVFormat.class));

        // Inject mocks and fields via reflection
        setField(parser, "lexer", lexerMock);
        setField(parser, "headerMap", headerMap);
        reusableToken = new Token();
        setField(parser, "reusableToken", reusableToken);
        recordList = new ArrayList<>();
        setField(parser, "record", recordList);
        setField(parser, "recordNumber", 0L);
    }

    private void setField(Object target, String fieldName, Object value) throws Exception {
        var field = CSVParser.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }

    private void setReusableTokenType(Token.Type type) {
        reusableToken.type = type;
    }

    private void setReusableTokenContent(String content) {
        reusableToken.content = content;
    }

    private void setReusableTokenIsReady(boolean isReady) {
        reusableToken.isReady = isReady;
    }

    private void addRecordValueSpy() throws Exception {
        // Spy on parser to verify addRecordValue is called
        var spyParser = spy(parser);
        doCallRealMethod().when(spyParser).nextRecord();

        // Replace parser with spy
        parser = spyParser;
    }

    @Test
    void testNextRecord_withTokensAndEORECORD() throws Exception {
        // Prepare token sequence: TOKEN, TOKEN, EORECORD
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "val1";
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "val2";
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EORECORD;
            reusableToken.content = "val3";
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        // Spy addRecordValue to add record values to record list
        doAnswer(invocation -> {
            recordList.add(reusableToken.content);
            return null;
        }).when(parser).addRecordValue();

        // Call nextRecord
        CSVRecord record = parser.nextRecord();

        // Verify record content and record number
        assertNotNull(record);
        assertArrayEquals(new String[] {"val1", "val2", "val3"}, record.values());
        assertEquals(1L, parser.getRecordNumber());
    }

    @Test
    void testNextRecord_withEOF_andIsReadyTrue() throws Exception {
        // Prepare token sequence: TOKEN, EOF (isReady true)
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.TOKEN;
            reusableToken.content = "val1";
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EOF;
            reusableToken.content = "val2";
            reusableToken.isReady = true;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        doAnswer(invocation -> {
            recordList.add(reusableToken.content);
            return null;
        }).when(parser).addRecordValue();

        CSVRecord record = parser.nextRecord();

        assertNotNull(record);
        assertArrayEquals(new String[] {"val1", "val2"}, record.values());
        assertEquals(1L, parser.getRecordNumber());
    }

    @Test
    void testNextRecord_withEOF_andIsReadyFalse() throws Exception {
        // Prepare token sequence: EOF (isReady false)
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.EOF;
            reusableToken.content = "val1";
            reusableToken.isReady = false;
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        // addRecordValue should not be called
        doThrow(new AssertionError("addRecordValue should not be called")).when(parser).addRecordValue();

        CSVRecord record = parser.nextRecord();

        assertNull(record);
        assertEquals(0L, parser.getRecordNumber());
    }

    @Test
    void testNextRecord_withCommentTokens() throws Exception {
        // Prepare token sequence: COMMENT, COMMENT, EORECORD
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.COMMENT;
            reusableToken.content = "comment1";
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.COMMENT;
            reusableToken.content = "comment2";
            return null;
        }).doAnswer(invocation -> {
            reusableToken.type = Token.Type.EORECORD;
            reusableToken.content = "val1";
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        // addRecordValue adds record values
        doAnswer(invocation -> {
            recordList.add(reusableToken.content);
            return null;
        }).when(parser).addRecordValue();

        CSVRecord record = parser.nextRecord();

        assertNotNull(record);
        assertArrayEquals(new String[] {"val1"}, record.values());
        assertEquals(1L, parser.getRecordNumber());
        assertEquals("comment1\ncomment2", record.getComment());
    }

    @Test
    void testNextRecord_withInvalidToken_throwsIOException() throws Exception {
        doAnswer(invocation -> {
            reusableToken.type = Token.Type.INVALID;
            reusableToken.content = "bad";
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        IOException ex = assertThrows(IOException.class, () -> parser.nextRecord());
        assertTrue(ex.getMessage().contains("invalid parse sequence"));
    }

    @Test
    void testNextRecord_withUnexpectedToken_throwsIllegalStateException() throws Exception {
        doAnswer(invocation -> {
            reusableToken.type = null; // unexpected token type
            return null;
        }).when(lexerMock).nextToken(reusableToken);

        IllegalStateException ex = assertThrows(IllegalStateException.class, () -> parser.nextRecord());
        assertTrue(ex.getMessage().contains("Unexpected Token type"));
    }
}

